// src/cancha/stat-card.js
// Componente HTML overlay para stats — se ancla a una posición 3D de la cancha

import * as THREE from 'three'

const _pos = new THREE.Vector3()

export function createStatCard(scene, camera, opciones = {}) {

  const {
    jugador  = { x: 25, z: 5, nombre: 'H. Martín', numero: 9 },  // #9 por defecto
    offsetY  = 24,   // altura en 3D sobre el jugador
    datos    = {
      titulo:     'Ball recovery',
      confianza1: 0.81,
      confianza2: 0.72,
    },
  } = opciones

  // ── Contenedor principal ──────────────────────────────────────────────────
  const wrapper = document.createElement('div')
  wrapper.id = 'stat-card-ball-recovery'
  wrapper.innerHTML = `
    <div class="sc-card">
      <div class="sc-corner-glow"></div>
      <div class="sc-header">
        <span class="sc-title">${datos.titulo}</span>
      </div>

      <div class="sc-ball-wrap">
        <img class="sc-ball" src="data:image/png;base64," alt="ball"/>
        <div class="sc-ball-glow"></div>
      </div>

      <div class="sc-metrics">
        <div class="sc-metric">
          <div class="sc-metric-row">
            <span class="sc-label">confianza</span>
            <span class="sc-value">${datos.confianza1.toFixed(2)}</span>
          </div>
          <div class="sc-bar-track">
            <div class="sc-bar-fill" style="width: ${datos.confianza1 * 100}%"></div>
          </div>
        </div>
        <div class="sc-metric">
          <div class="sc-metric-row">
            <span class="sc-label">confianza</span>
            <span class="sc-value">${datos.confianza2.toFixed(2)}</span>
          </div>
          <div class="sc-bar-track">
            <div class="sc-bar-fill sc-bar-fill--alt" style="width: ${datos.confianza2 * 100}%"></div>
          </div>
        </div>
      </div>
    </div>
  `

  // ── Estilos ───────────────────────────────────────────────────────────────
  const style = document.createElement('style')
  style.textContent = `
    #stat-card-ball-recovery {
      position: fixed;
      pointer-events: none;
      z-index: 100;
      transition: opacity 0.3s;
    }

    .sc-card {
      box-sizing: border-box;
      display: flex;
      flex-direction: column;
      align-items: center;
      padding: 24px 24px 40px 24px;
      gap: 48px;
      isolation: isolate;
      width: 341.34px;
      background: rgba(11, 21, 33, 0.5);
      border: 1px solid rgba(100, 200, 255, 0.35);
      box-shadow: 0px 8px 32px rgba(0, 0, 0, 0.37),
                  0 0 0 1px rgba(42, 186, 220, 0.2),
                  0 0 12px rgba(42, 186, 220, 0.25),
                  0 0 30px rgba(37, 159, 235, 0.1),
                  0 0 20px rgba(37, 159, 235, 0.08) inset;
      backdrop-filter: blur(12px);
      border-radius: 20px;
      font-family: 'Barlow', 'Barlow Condensed', sans-serif;
      position: relative;
      overflow: hidden;
    }

    .sc-corner-glow {
      position: absolute;
      width: 128px;
      height: 128px;
      right: -38.99px;
      top: -39px;
      background: rgba(37, 159, 235, 0.1);
      filter: blur(20px);
      border-radius: 9999px;
      flex: none;
      order: 0;
      flex-grow: 0;
      z-index: 0;
      pointer-events: none;
    }

    .sc-header {
      width: 100%;
      text-align: left;
    }

    .sc-title {
      font-family: 'Poppins', sans-serif;
      font-weight: 500;
      font-size: 18px;
      color: #ffffff;
      letter-spacing: 0.01em;
    }

    .sc-ball-wrap {
      position: relative;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 130px;
      margin-bottom: 16px;
    }

    .sc-ball {
      width: 150px;
      height: 150px;
      object-fit: contain;
      filter: drop-shadow(0 0 20px rgba(42,186,220,0.6))
              drop-shadow(0 0 50px rgba(20,120,200,0.35));
      animation: sc-float 3s ease-in-out infinite;
    }

    .sc-ball-glow {
      position: absolute;
      width: 80px;
      height: 20px;
      bottom: 4px;
      background: radial-gradient(ellipse, rgba(42,186,220,0.25) 0%, transparent 70%);
      border-radius: 50%;
      animation: sc-float 3s ease-in-out infinite reverse;
    }

    @keyframes sc-float {
      0%, 100% { transform: translateY(0px); }
      50%       { transform: translateY(-6px); }
    }

    .sc-metrics {
      display: flex;
      flex-direction: column;
      gap: 12px;
      width: 100%;
    }

    .sc-metric-row {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 8px;
    }

    .sc-label {
      font-family: 'JetBrains Mono', monospace;
      font-style: normal;
      font-weight: 400;
      font-size: 12px;
      line-height: 15px;
      color: rgba(255, 255, 255, 0.72);
      flex: none;
      order: 0;
      flex-grow: 0;
    }

    .sc-value {
      font-family: 'JetBrains Mono', monospace;
      font-style: normal;
      font-weight: 300;
      font-size: 12px;
      line-height: 15px;
      display: flex;
      align-items: center;
      text-align: right;
      color: #94A3B8;
      flex: none;
      order: 1;
      flex-grow: 1;
      justify-content: flex-end;
    }

    .sc-bar-track {
      height: 3px;
      background: rgba(255,255,255,0.08);
      border-radius: 2px;
      overflow: hidden;
    }

    .sc-bar-fill {
      height: 100%;
      border-radius: 2px;
      background: linear-gradient(90deg, #1a5adc 0%, #2abadc 100%);
      box-shadow: 0 0 6px rgba(42,186,220,0.6);
    }

    .sc-bar-fill--alt {
      background: linear-gradient(90deg, #0a3aaa 0%, #1a7adc 100%);
    }
  `

  document.head.appendChild(style)
  document.body.appendChild(wrapper)

  // ── Proyectar posición del jugador en 2D y poner card 20px arriba ─────────
  const pos3D = new THREE.Vector3(jugador.x, jugador.y ?? 8, jugador.z)

  function tickStatCard() {
    _pos.copy(pos3D)
    _pos.project(camera)

    if (_pos.z > 1) { wrapper.style.opacity = '0'; return }
    wrapper.style.opacity = '1'

    const x = ( _pos.x * 0.5 + 0.5) * window.innerWidth
    const y = (-_pos.y * 0.5 + 0.5) * window.innerHeight

    // Centrar horizontalmente y posicionar 20px arriba de la cabeza del jugador
    wrapper.style.left      = x + 'px'
    wrapper.style.top       = (y - 85) + 'px'
    wrapper.style.transform = 'translate(-50%, -100%)'
  }

  // ── Botón de toggle ───────────────────────────────────────────────────────
  let visible = false
  wrapper.style.display = 'none'

  const btn = document.createElement('button')
  btn.textContent = 'Ball Recovery'
  btn.className   = 'btn'
  btn.addEventListener('click', function () {
    visible = !visible
    wrapper.style.display = visible ? 'block' : 'none'
    this.classList.toggle('active', visible)
  })
  document.getElementById('cc-controls').appendChild(btn)

  return { wrapper, tickStatCard }
}
